// kernel/kernel_cpu.c
#include <stdio.h>
#include <stdlib.h>
#include <omp.h>
#include "../main.h" // include main.h from the parent directory

void kernel_cpu(par_str par, dim_str dim, box_str* box, FOUR_VECTOR* rv, fp* qv, FOUR_VECTOR* fv) {

    // THREAD PARAMETERS
    int bx, tx;

    // DO FOR THE NUMBER OF BOXES
    #pragma omp parallel for private(bx, tx)
    for(bx = 0; bx < dim.number_boxes; bx++) {

        // Extract input parameters
        fp a2 = 2.0 * par.alpha * par.alpha;

        // Home box
        int first_i;
        FOUR_VECTOR* rA;
        FOUR_VECTOR* fA;

        // Nei box
        int pointer;
        int k = 0;
        int first_j;
        FOUR_VECTOR* rB;
        fp* qB;
        int j = 0;

        // Common
        fp r2;
        fp u2;
        fp vij;
        fp fs;
        fp fxij;
        fp fyij;
        fp fzij;
        THREE_VECTOR d;

        // Home box
        first_i = box[bx].offset;
        rA = &rv[first_i];
        fA = &fv[first_i];

        // Nei box loop
        for (k = 0; k < (1 + box[bx].nn); k++) {

            // Nei box - get pointer to the right box
            if (k == 0) {
                pointer = bx; // set first box to be processed to home box
            }
            else {
                pointer = box[bx].nei[k - 1].number; // remaining boxes are nei boxes
            }

            // Nei box - box parameters
            first_j = box[pointer].offset;

            // Nei box - distance, (force), charge and (type) parameters
            rB = &rv[first_j];
            qB = &qv[first_j];

            // Calculation
            #pragma omp parallel for private(j, r2, u2, vij, fs, fxij, fyij, fzij, d)
            for (tx = 0; tx < NUMBER_PAR_PER_BOX; tx++) {

                // Loop for the number of particles in the current nei box
                for (j = 0; j < NUMBER_PAR_PER_BOX; j++) {

                    r2 = (fp)rv[first_i + tx].v + (fp)rv[first_j + j].v - DOT((fp)rv[first_i + tx], (fp)rv[first_j + j]);
                    u2 = a2 * r2;
                    vij = exp(-u2);
                    fs = 2 * vij;

                    d.x = (fp)rv[first_i + tx].x - (fp)rv[first_j + j].x;
                    fxij = fs * d.x;
                    d.y = (fp)rv[first_i + tx].y - (fp)rv[first_j + j].y;
                    fyij = fs * d.y;
                    d.z = (fp)rv[first_i + tx].z - (fp)rv[first_j + j].z;
                    fzij = fs * d.z;

                    fv[first_i + tx].v += (double)((fp)qv[first_j + j] * vij);
                    fv[first_i + tx].x += (double)((fp)qv[first_j + j] * fxij);
                    fv[first_i + tx].y += (double)((fp)qv[first_j + j] * fyij);
                    fv[first_i + tx].z += (double)((fp)qv[first_j + j] * fzij);

                }

            }

        }

    }

}

